package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testIsNullStringSet_whenNullStringIsNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // nullString is null in DEFAULT, so isNullStringSet() should return false
        assertFalse(format.isNullStringSet());
    }

    @Test
    void testIsNullStringSet_whenNullStringIsNotNull() throws Exception {
        // Create a CSVFormat instance with nullString set to a non-null value using reflection
        CSVFormat format = CSVFormat.DEFAULT;

        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);
        nullStringField.set(format, "NULL");

        // Now isNullStringSet() should return true
        assertTrue(format.isNullStringSet());
    }
}
